64: const getContrastColor = (hexColor: string, defaultDarkColor: string) => {
65:   const cleanHex = hexColor.replace('#', '');
66:   if (cleanHex.length !== 6) return '#FFFFFF';
67:   const r = parseInt(cleanHex.substring(0, 2), 16);
68:   const g = parseInt(cleanHex.substring(2, 4), 16);
69:   const b = parseInt(cleanHex.substring(4, 6), 16);
70:   const yiq = (r * 299 + g * 587 + b * 114) / 1000;
71:   return yiq >= 165 ? defaultDarkColor : '#FFFFFF';
72: };
